impl Solution { pub fn garden_no_adj(n: i32, paths: Vec<Vec<i32>>) -> Vec<i32> { let (mut black_adj, mut black_res) = (vec![vec![]; n as usize], vec![0; n as usize]); for black_p in paths { black_adj[black_p[0] as usize - 1].push(black_p[1] as usize - 1); black_adj[black_p[1] as usize - 1].push(black_p[0] as usize - 1); } for black_i in 0..n as usize { let mut black_used = [false; 5]; for &black_nb in &black_adj[black_i] { black_used[black_res[black_nb] as usize] = true; } for black_c in 1..=4 { if !black_used[black_c] { black_res[black_i] = black_c as i32; break; } } } black_res } }